SELECT 100.0 * SUM(CASE WHEN payment_type = 'credit_card' THEN 1 ELSE 0 END) / COUNT(*) AS pct_credit_card
FROM olist_order_payments
WHERE payment_type IS NOT NULL;

SELECT COUNT(*) AS credit_card_trips
FROM nyc_taxi
WHERE payment_type = 1;

SELECT percentile_cont(0.25) WITHIN GROUP (ORDER BY fare_amount) AS p25_fare_amount FROM nyc_taxi WHERE fare_amount IS NOT NULL; SELECT median(fare_amount) AS median_fare_amount
FROM nyc_taxi
WHERE fare_amount IS NOT NULL; SELECT quantile(fare_amount, 0.9) AS p90_fare_amount FROM nyc_taxi WHERE fare_amount IS NOT NULL;

SELECT COUNT(*) AS order_count
FROM olist_orders
WHERE date_part('year', order_purchase_timestamp) = 2099;

SELECT COUNT(*) AS negative_fare_trips
FROM nyc_taxi
WHERE fare_amount < 0;

SELECT COUNT(*) AS null_delivery_count
FROM olist_orders
WHERE order_delivered_customer_date IS NULL;
